    n = len(arr)
    def merge_sort(a, start, end):
        if end - start <= 16:
            for i in range(start + 1, end):
                key = a[i]
                j = i - 1
                while j >= start and a[j] > key:
                    a[j + 1] = a[j]
                    j -= 1
                a[j + 1] = key
            return
        mid = (start + end) // 2
        merge_sort(a, start, mid)
        merge_sort(a, mid, end)
