                merged.append(a[j])
                j += 1
        while i < mid:
            merged.append(a[i])
            i += 1
        while j < end:
            merged.append(a[j])
            j += 1
        a[start:end] = merged
    merge_sort(arr, 0, n)
    return arr

def fast_sort(arr):
    if not arr:
        return []
    arr = list(arr)
    min_val = min(arr)
    arr = [x - min_val for x in arr]
    max_val = max(arr)
    if max_val == 0:
        return [min_val] * len(arr)
    def radix_msd(a, bit):
        if len(a) <= 1 or bit < 0:
            return a
        zeros = []
        ones = []
        for x in a:
            if (x >> bit) & 1:
                ones.append(x)
            else:
                zeros.append(x)
        return radix_msd(zeros, bit - 1) + radix_msd(ones, bit - 1)
    bits = max_val.bit_length() - 1 if max_val > 0 else 0
    result = radix_msd(arr, bits)
    return [x + min_val for x in result]

