def _three_way_qs(arr, lo, hi):
    if lo >= hi:
        return
    pivot = arr[(lo + hi) // 2]
    lt = lo
    gt = hi
    i = lo
    while i <= gt:
        if arr[i] < pivot:
            arr[lt], arr[i] = arr[i], arr[lt]
            lt += 1
            i += 1
        elif arr[i] > pivot:
            arr[gt], arr[i] = arr[i], arr[gt]
            gt -= 1
        else:
            i += 1
    _three_way_qs(arr, lo, lt - 1)
    _three_way_qs(arr, gt + 1, hi)

def fast_sort(arr):
    if len(arr) <= 1:
        return list(arr)
    arr = list(arr)
    n = len(arr)
    min_run = 32
    def insertion_sort_run(a, lo, hi):
        for i in range(lo + 1, hi + 1):
            key = a[i]
            j = i - 1
            while j >= lo and a[j] > key:
                a[j + 1] = a[j]
                j -= 1
            a[j + 1] = key
    def merge_runs(a, lo, mid, hi):
        left = a[lo:mid + 1]
        right = a[mid + 1:hi + 1]
        i = j = 0
        k = lo
        while i < len(left) and j < len(right):
            if left[i] <= right[j]:
                a[k] = left[i]
                i += 1
            else:
                a[k] = right[j]
                j += 1
            k += 1
        while i < len(left):
            a[k] = left[i]
            i += 1
            k += 1
        while j < len(right):
            a[k] = right[j]
            j += 1
            k += 1
    for start in range(0, n, min_run):
        end = min(start + min_run - 1, n - 1)
        insertion_sort_run(arr, start, end)
    size = min_run
    while size < n:
        for left_start in range(0, n, 2 * size):
            mid = min(left_start + size - 1, n - 1)
            right_end = min(left_start + 2 * size - 1, n - 1)
            if mid < right_end:
                merge_runs(arr, left_start, mid, right_end)
        size *= 2
    return arr
